import{_ as t,a,b as r}from"./chunks/配置渠道内容.HzNkdrom.js";import{_ as i,o,c as s,a2 as d}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Ajouter un canal GitLab Packages","description":"","frontmatter":{},"headers":[],"relativePath":"fr-FR/upload/gitlab-packages.md","filePath":"fr-FR/upload/gitlab-packages.md","lastUpdated":1781962217000}'),n={name:"fr-FR/upload/gitlab-packages.md"};function l(c,e,p,u,h,g){return o(),s("div",null,[...e[0]||(e[0]=[d('<h1 id="ajouter-un-canal-gitlab-packages" tabindex="-1">Ajouter un canal GitLab Packages <a class="header-anchor" href="#ajouter-un-canal-gitlab-packages" aria-label="Permalink to &quot;Ajouter un canal GitLab Packages&quot;">​</a></h1><p>Le canal GitLab Packages utilise le Generic Package Registry de GitLab comme stockage.</p><h2 id="a-preparer" tabindex="-1">À préparer <a class="header-anchor" href="#a-preparer" aria-label="Permalink to &quot;À préparer&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Élément</th><th>Utilité</th></tr></thead><tbody><tr><td>Compte GitLab</td><td>Gérer projet et token</td></tr><tr><td>Projet GitLab</td><td>Emplacement du paquet</td></tr><tr><td>Access Token</td><td>Envoyer des fichiers au Package Registry</td></tr><tr><td>Project ID</td><td>Identifier le projet dans ImgBed</td></tr></tbody></table><h2 id="creer-le-token" tabindex="-1">Créer le token <a class="header-anchor" href="#creer-le-token" aria-label="Permalink to &quot;Créer le token&quot;">​</a></h2><p>Dans GitLab, créez un Access Token avec les permissions nécessaires.</p><p><img src="'+t+'" alt="Générer le token" loading="lazy"></p><p>Cochez les permissions de lecture et écriture nécessaires pour les packages.</p><p><img src="'+a+'" alt="Permissions du token" loading="lazy"></p><p>Le token peut n’être affiché qu’une seule fois. Copiez-le et conservez-le.</p><h2 id="renseigner-dans-imgbed" tabindex="-1">Renseigner dans ImgBed <a class="header-anchor" href="#renseigner-dans-imgbed" aria-label="Permalink to &quot;Renseigner dans ImgBed&quot;">​</a></h2><p>Dans Paramètres d’upload, choisissez <code>GitLab Packages</code>.</p><table tabindex="0"><thead><tr><th>Champ</th><th>Valeur</th></tr></thead><tbody><tr><td>Nom du canal</td><td>Par exemple <code>GitLab Packages</code></td></tr><tr><td>GitLab Host</td><td><code>https://gitlab.com</code> ou votre instance</td></tr><tr><td>Project ID</td><td>ID du projet</td></tr><tr><td>Token</td><td>Access Token</td></tr><tr><td>Package Name</td><td>Nom du paquet</td></tr><tr><td>Version</td><td>Version</td></tr><tr><td>Chemin</td><td>Optionnel</td></tr></tbody></table><p><img src="'+r+'" alt="Configuration GitLab" loading="lazy"></p><h2 id="verification" tabindex="-1">Vérification <a class="header-anchor" href="#verification" aria-label="Permalink to &quot;Vérification&quot;">​</a></h2><ol><li>Enregistrez le canal.</li><li>Envoyez un fichier de test.</li><li>Vérifiez qu’il apparaît dans le Package Registry.</li><li>Ouvrez le lien via ImgBed.</li></ol><h2 id="erreurs-courantes" tabindex="-1">Erreurs courantes <a class="header-anchor" href="#erreurs-courantes" aria-label="Permalink to &quot;Erreurs courantes&quot;">​</a></h2><ul><li>Project ID incorrect.</li><li>Token sans droit d’écriture sur le Package Registry.</li><li>GitLab Host mal saisi.</li><li>Package Registry désactivé dans le projet.</li></ul>',18)])])}const f=i(n,[["render",l]]);export{k as __pageData,f as default};
